def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0 or item > capacity:
            continue
        ratio = item / capacity
        base_score = 0
        for p in range(1, 20):
            pow_term = (ratio ** p) / (p**3)
            if p % 4 == 0:
                pow_term *= 1.3
            elif p % 3 == 0:
                pow_term *= 1.15
            elif p % 5 == 0:
                pow_term *= 0.85
            else:
                pow_term *= 0.9
            base_score += pow_term
        remaining = capacity - item
        if remaining < 0.02 * capacity:
            base_score *= 3.0
        elif remaining < 0.07 * capacity:
            base_score *= 1.8
        elif remaining < 0.15 * capacity:
            base_score *= 1.2
        else:
            base_score *= 0.65
        mod_factors = [3,5,7,11]
        mod_scores = [0.1,0.15,0.12,0.2]
        mod_sum = 0
        for mf, ms in zip(mod_factors, mod_scores):
            if int(capacity) % mf == 0:
                mod_sum += ms * (capacity / (10 * mf))
        base_score -= mod_sum
        complex_penalty = 0
        for k in range(1,8):
            scale = 0.01 * capacity * k
            diff = abs(capacity - item * k)
            if diff < scale:
                complex_penalty += 0.3 * k
            elif diff < 2 * scale:
                complex_penalty += 0.15 * k
            elif diff < 3 * scale:
                complex_penalty += 0.05 * k
            else:
                complex_penalty -= 0.07 * k
        cycle_penalty = 0
        for c in range(1,5):
            segment = capacity / c
            if abs(item - segment) < 0.03 * segment:
                cycle_penalty += 0.1 * c
            elif abs(item - segment) < 0.05 * segment:
                cycle_penalty -= 0.05 * c
            else:
                cycle_penalty -= 0.1 * c
        base_score += complex_penalty + cycle_penalty
        if base_score < 0:
            base_score = 0
        if base_score > 2.0:
            multiplier = 1.0
            for m in range(1,5):
                target = capacity / m
                if abs(item - target) < 0.015 * target:
                    multiplier += 0.07 * m
                else:
                    multiplier -= 0.02 * m
            base_score *= multiplier
            if base_score < 0:
                base_score = 0
        priorities[i] = base_score
    return priorities
